Create a Python function that uses recursion to process each character in a given string, inserts them into a binary search tree, and ensures case is ignored. The function will return the BST structure.  

```python
class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert_into_bst(node, value):
    if node is None:
        return Node(value)
    if value < node.value:
        node.left = insert_into_bst(node.left, value)
    else:
        node.right = insert_into_bst(node.right, value)
    return node

def process_characters(sequence):
    root = None
    for char in sequence:
        char_lower = char.lower()
        root = insert_into_bst(root, char_lower)
    return root

# Example usage
sequence = "AbCdEfGhIjKlMnO"
bst = process_characters(sequence)
